module RefModule(
    input clk, // Added clk input to resolve the error
    input a, b, c,
    output w, x, y, z
);reg a_reg, b_reg, c_reg;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
    a_reg <= a;
    b_reg <= b;
    c_reg <= c;
end

assign w = a_reg;
assign x = b_reg;
assign y = b_reg;
assign z = c_reg;

endmodule
